 46	/* this function must be called for each random process  and each time it shall produce a new random sample,
 47	 which is the return value
 48	 input:   - inputSamples: an array of length TARMA_NUM_PROCESSES with iid gaussian samples
 49	        which must be the same for xcorrelated processes
 50	      - proc: pointer to tarmaProcess_t
 51	 output:  - the next value in the random process
 52	*/
 53	double tarmaCalculateSample( double inputSamples[], tarmaProcess_t *proc)
 54	{
 55	  /* struct with all definitions of the random process and its history */
 56	  int cnt;
 57	  double X, Y, Ypower, Z;
 58	
 59	  /* calculate the current sample X' by weighting the input samples */
 60	  X=0;
 61	
 62	  for( cnt=0; cnt<TARMA_NUM_PROCESSES ; cnt++) {
 63	    X += proc->inputWeight[cnt]*inputSamples[cnt];
 64	  }
 65	
 66	  /* update the MA history: shift everything back for one lag */
 67	  for( cnt=TARMA_NUM_MA_MAX-1; cnt>0; cnt--) {
 68	    proc->maHist[cnt] = proc->maHist[cnt-1];
 69	  }
 70	
 71	  proc->maHist[0]=X;  /* update the MA history with the current filter input value */
 72	
 73	  /* update the AR history: shift everything back for one lag */
 74	  for( cnt=TARMA_NUM_AR_MAX-1; cnt>0; cnt--) {
 75	    proc->arHist[cnt] = proc->arHist[cnt-1];
 76	  }
 77	
 78	  proc->arHist[0]=0;  /* caution: arHist[0] must not be used for the filter processing! */
 79	
 80	  /* filter processing */
 81	  Y=0;
 82	
 83	  for( cnt=0; cnt<TARMA_NUM_MA_MAX; cnt++) { /* moving average part, start at lag 0 = current X */
 84	    Y += proc->maWeight[cnt] * proc->maHist[cnt];
 85	  }
 86	
 87	  for( cnt=1; cnt<TARMA_NUM_AR_MAX; cnt++) { /* auto regressive part, start at lag 1 = former Y */
 88	    Y += -proc->arWeight[cnt] * proc->arHist[cnt];
 89	  }
 90	
 91	  proc->arHist[0]=Y;  /* update the AR history with the current filter output value */
 92	
 93	  /* polynomial transformation */
 94	  Z=0;
 95	  Ypower=1;
 96	
 97	  for(cnt=0; cnt<TARMA_NUM_POLY_MAX; cnt++) {
 98	    Z += proc->polyWeight[cnt]*Ypower;
 99	    Ypower *= Y;
100	  }
101	
102	  LOG_D(OTG,"TARMA_DEBUG: tarmaCalculateSamples called: Z=%f\n",Z);
103	  //tarmaPrintProc(proc);
104	  return Z;
105	}
