107	/*
108	 this function must be called each time before size and itd are generated for the respective packet.
109	  it updates the input samples stored in the structure stream,
110	  ps: calling it more often than for each packet is also fine
111	 input:   - the stream to be updated
112	 output:
113	 */
114	void tarmaUpdateInputSample (tarmaStream_t *stream)
115	{
116	  int cnt;
117	  LOG_T(OTG,"TARMA_DEBUG: tarmaUpdateInputSample(%p)\n", stream);
118	
119	  if(stream) {
120	    for(cnt=0; cnt<TARMA_NUM_PROCESSES; cnt++) {
121	      stream->tarma_input_samples[cnt]=gaussian_dist(10000,1)-10000;
122	      LOG_D(OTG,"TARMA_DEBUG:   %f\n",stream->tarma_input_samples[cnt]);
123	    }
124	  }
125	}
